// ═══════════════════════════════════════════════
// SAFE JSON PARSER & CLEANER NODE (REPLACES PARSER NODE)
// ═══════════════════════════════════════════════

// 1. هات النص اللي خارج من الـ Agent
let rawText = $input.item.json.output; 

if (!rawText) {
    return [{ json: { error: "No output found from AI Agent." } }];
}

// 2. تنظيف النص لو الـ AI استهبل وحط علامات ```json
rawText = rawText.trim();
if (rawText.startsWith("```json")) {
    rawText = rawText.replace(/^```json/, "").replace(/```$/, "").trim();
} else if (rawText.startsWith("```")) {
    rawText = rawText.replace(/^```/, "").replace(/```$/, "").trim();
}

let parsedJson;
try {
    // 3. محاولة تحويل النص لـ JSON حقيقي
    parsedJson = JSON.parse(rawText);
} catch (e) {
    // لو الـ JSON فيه غلطة، بنحاول نلقط أول { وأخر } عشان ننقذ الداتا
    const startIdx = rawText.indexOf('{');
    const endIdx = rawText.lastIndexOf('}');
    if (startIdx !== -1 && endIdx !== -1) {
        try {
            parsedJson = JSON.parse(rawText.substring(startIdx, endIdx + 1));
        } catch (innerError) {
            return [{ json: { error: "Failed to parse JSON even after cleaning.", details: e.message, raw: rawText } }];
        }
    } else {
        return [{ json: { error: "Response is not a valid JSON structure.", raw: rawText } }];
    }
}

// 4. ترتيب وتأمين الـ 12 Performance Criteria والـ Knowledge كاملين دون أي نقص
if (parsedJson.units_list && Array.isArray(parsedJson.units_list)) {
    parsedJson.units_list.forEach(unit => {
        if (unit.performance_criteria_list && Array.isArray(unit.performance_criteria_list)) {

            // ترتيب الـ PCs تصاعدياً (PC 1, PC 2 ... PC 12) لضمان سلامة العرض
            unit.performance_criteria_list.sort((a, b) => {
                const numA = parseInt(a.pc_code.replace(/\D/g, '')) || 0;
                const numB = parseInt(b.pc_code.replace(/\D/g, '')) || 0;
                return numA - numB;
            });

            unit.performance_criteria_list.forEach(pc => {
                // التأكد التام إن الـ related_knowledge واصلة كـ Array سليم ومطابق للبرومبت
                if (Array.isArray(pc.related_knowledge)) {
                    // إذا جاءت جاهزة ومقسمة كـ Objects أو Strings بنسيبها تعبر بسلاسة
                } else if (typeof pc.related_knowledge === 'string') {
                    // لو الـ AI استسهل وكتبها نص مجمع بنفصلها لـ Objects نظيفة
                    pc.related_knowledge = pc.related_knowledge.split(/\n|,|;/).map(l => ({ code: "", text: l.trim() })).filter(l => l.text.length > 0);
                } else {
                    pc.related_knowledge = [];
                }
            });
        }
    });
}

// بنرجع الداتا جوه مفتاح اسمه "output" عشان نود الـ HTML بتاعتك متقراش غلط
return [{ json: { output: parsedJson } }];

