function renderCareerPath(pathString) {
    if (!pathString || pathString === "N/A") return `<p style="color:#666;">No career path data available.</p>`;
    const levels = pathString.split("->").map(s => s.trim());
    if (levels.length <= 1) return `<p style="line-height:1.8; font-weight:bold;">${pathString}</p>`;

    let htmlMarkup = `<div style="width:100%; text-align:center; margin:15px 0;">`;
    levels.reverse().forEach((lvl, idx) => {
        let width = 90 - (idx * 12);
        if (width < 40) width = 40;
        htmlMarkup += `
        <div style="width:${width}%; background:#FFFDF0; border:1px solid #FFC000; padding:8px; margin:4px auto; font-weight:bold; font-size:12px; color:#000000;">
            ${lvl}
        </div>`;
    });
    htmlMarkup += `</div>`;
    return htmlMarkup;
}

function cleanPcText(text) {
    if (!text) return "";
    return text.replace(/^(The individual must be able to:|The individual should be able to:)\s*/i, "").trim();
