// ═══════════════════════════════════════════════
// إضافة صفحة الاختصارات ديناميكياً في آخر الملف تماماً (خارج حلقة الوحدات)
// ═══════════════════════════════════════════════
let abbrevList = [];
if (inputData.abbreviations && Array.isArray(inputData.abbreviations)) {
    abbrevList = inputData.abbreviations;
} else if (inputData.abbreviations_list && Array.isArray(inputData.abbreviations_list)) {
    abbrevList = inputData.abbreviations_list;
} else {
    // القاموس الاحتياطي القياسي في حال عدم إرسال داتا عبر النود
    const refDict = {
        "NOS": "National Occupational Standards",
        "MOL": "Ministry of Labour",
        "US": "Unit Standard",
        "OQF": "Oman Qualification Framework",
        "PC": "Performance Criteria",
        "K": "Knowledge",
        "PPE": "Personal Protective Equipment",
        "HSE": "Health, Safety and Environment"
    };
    Object.keys(refDict).forEach(k => abbrevList.push({ term: k, explanation: refDict[k] }));
}

if (abbrevList.length > 0) {
    html += `<div class="page-break"></div>
    <table style="margin-top:0;">
      <thead>
        <tr><th colspan="2" style="background:#FFC000; color:#000000; text-align:left; padding:8px 12px; font-weight:bold;">ABBREVIATIONS AND TECHNICAL TERMS</th></tr>
        <tr>
          <td class="hdr-sub" style="width:30%; font-weight:bold; background:#FFF9E6; text-align:center;">Abbreviation / Term</td>
          <td class="hdr-sub" style="font-weight:bold; background:#FFF9E6; text-align:left; padding-left:15px;">Explanation</td>
        </tr>
      </thead>
      <tbody>
        ${abbrevList.map(item => {
            const termStr = item.term || item.abbreviation || Object.keys(item)[0] || "N/A";
            const expStr = item.explanation || item.description || Object.values(item)[0] || "N/A";
            return `<tr>
                <td style="font-weight:bold; text-align:center; background:#fdfdfd; font-family:monospace; font-size:12px;">${termStr}</td>
                <td style="padding:7px 12px; text-align:justify; line-height:1.5;">${expStr}</td>
            </tr>`;
        }).join('')}
      </tbody>
    </table>`;

    html += officialFooterHtml;
}

html += `</body></html>`;

return [{ json: { html: html } }];
